@vex.guardrail('conversation-coherence')
def check_coherence(state: ConversationState, new_response: VoiceResponse) -> bool:
    if not state.history:
        return True

    last_user = state.history[-1]['input']
    last_ai = state.history[-2]['output'].response_text if len(state.history) > 1 else ''

    # Check topical continuity
    continuity_score = semantic_similarity(last_user, new_response.response_text)

    return (
        continuity_score > 0.6 and
        new_response.confidence > 0.7 and
        len(new_response.response_text) > 5
    )

# Integrated into stateful processing
async def coherent_process(state: ConversationState, text: str) -> VoiceResponse:
    result = await voice_agent_with_vex.run(text)
    if not check_coherence(state, result):
        result.response_text = "Let me clarify that for you..."
    return result
